import React from 'react';
import type { DailyCashDayDto } from '../../../../services/fpc/types';
import styles from '../DailyCashForecastPage.module.css';

interface ForecastTableProps {
  days: DailyCashDayDto[];
  minimumCashBuffer: number;
}

/**
 * Format a number in compact VND style.
 */
function fmt(value: number): string {
  if (value == null || Number.isNaN(value)) return '—';
  const abs = Math.abs(value);
  const sign = value < 0 ? '-' : '';
  if (abs >= 1_000_000_000) return `${sign}${(abs / 1_000_000_000).toFixed(2)} tỷ`;
  if (abs >= 1_000_000) return `${sign}${(abs / 1_000_000).toFixed(0)} tr`;
  return `${sign}${abs.toLocaleString('vi-VN')}`;
}

/**
 * Format full number with commas.
 */
function fmtFull(value: number): string {
  if (value == null || Number.isNaN(value)) return '—';
  return value.toLocaleString('vi-VN');
}

function getAlertIcon(status: string): React.ReactNode {
  switch (status) {
    case 'critical':
      return (
        <span className={styles.redDateBadge} title="Ngày đỏ">
          <i className="fas fa-exclamation-circle" />
        </span>
      );
    case 'warning':
      return (
        <span className={styles.alertBadge} title="Cảnh báo">
          <i className="fas fa-exclamation-triangle" />
        </span>
      );
    default:
      return (
        <span className={styles.safeBadge} title="An toàn">
          <i className="fas fa-check-circle" />
        </span>
      );
  }
}

function getRowClass(status: string): string {
  switch (status) {
    case 'critical': return `${styles.rowRedDate}`;
    case 'warning': return `${styles.rowAlert}`;
    default: return '';
  }
}

const ForecastTable: React.FC<ForecastTableProps> = ({ days, minimumCashBuffer }) => {
  if (days.length === 0) {
    return (
      <div className={styles.tableCard}>
        <div className={styles.tableEmpty}>
          <i className="fas fa-calendar-alt" />
          <p>Chưa có dữ liệu dự báo theo ngày. Vui lòng chọn kỳ và nhấn <strong>Xem</strong>.</p>
        </div>
      </div>
    );
  }

  // Compute totals row
  const totalOpening = days[0]?.openingBalance ?? 0;
  const totalInflow = days.reduce((s, d) => s + d.inflowPlanned, 0);
  const totalOutflow = days.reduce((s, d) => s + d.outflowPlanned, 0);
  const totalNet = totalInflow - totalOutflow;
  const totalClosing = days[days.length - 1]?.closingBalance ?? 0;
  const totalMandatory = days.reduce((s, d) => s + d.mandatoryOutflow, 0);
  const totalAvailable = days[days.length - 1]?.availableBalance ?? 0;

  return (
    <div className={styles.tableCard}>
      <div className={styles.tableWrapper}>
        <table className={styles.table} data-testid="forecast-days-table">
          <thead>
            <tr>
              <th className={styles.colNo}>#</th>
              <th className={styles.colDate}>Ngày</th>
              <th className={styles.colAmount}>Số dư đầu</th>
              <th className={styles.colAmount}>Tổng thu</th>
              <th className={styles.colAmount}>Tổng chi</th>
              <th className={styles.colAmount}>LCTT</th>
              <th className={styles.colAmount}>Số dư cuối</th>
              <th className={styles.colAmount}>Chi bắt buộc</th>
              <th className={styles.colAmount}>Tiền khả dụng</th>
              <th className={styles.colAlert}>T.trạng</th>
            </tr>
          </thead>
          <tbody>
            {days.map((day, idx) => (
              <tr key={day.date} className={getRowClass(day.alertStatus)}>
                <td className={styles.colNo}>{idx + 1}</td>
                <td className={styles.colDate}>
                  <span className={styles.dayLabel}>
                    {day.label}
                    {getAlertIcon(day.alertStatus)}
                  </span>
                </td>
                <td className={styles.colAmount}>{fmt(day.openingBalance)}</td>
                <td className={`${styles.colAmount} ${styles.positive}`}>+{fmt(day.inflowPlanned)}</td>
                <td className={`${styles.colAmount} ${styles.negative}`}>-{fmt(day.outflowPlanned)}</td>
                <td className={`${styles.colAmount} ${day.netCashflow >= 0 ? styles.positive : styles.negative}`}>
                  {fmt(day.netCashflow)}
                </td>
                <td className={`${styles.colAmount} ${day.closingBalance >= 0 ? styles.positive : styles.negative}`}>
                  {fmt(day.closingBalance)}
                </td>
                <td className={styles.colAmount}>{fmt(day.mandatoryOutflow)}</td>
                <td className={`${styles.colAmount} ${day.availableBalance >= 0 ? styles.positive : styles.negative}`}>
                  {fmt(day.availableBalance)}
                </td>
                <td className={styles.colAlert}>
                  {getAlertIcon(day.alertStatus)}
                </td>
              </tr>
            ))}
            {/* Total row */}
            <tr className={styles.rowTotal}>
              <td className={styles.colNo} />
              <td className={styles.colDate}>
                <strong>Tổng cộng</strong>
              </td>
              <td className={styles.colAmount}>{fmt(totalOpening)}</td>
              <td className={`${styles.colAmount} ${styles.positive}`}>+{fmt(totalInflow)}</td>
              <td className={`${styles.colAmount} ${styles.negative}`}>-{fmt(totalOutflow)}</td>
              <td className={`${styles.colAmount} ${totalNet >= 0 ? styles.positive : styles.negative}`}>
                {fmt(totalNet)}
              </td>
              <td className={`${styles.colAmount} ${totalClosing >= 0 ? styles.positive : styles.negative}`}>
                {fmt(totalClosing)}
              </td>
              <td className={styles.colAmount}>{fmt(totalMandatory)}</td>
              <td className={`${styles.colAmount} ${totalAvailable >= 0 ? styles.positive : styles.negative}`}>
                {fmt(totalAvailable)}
              </td>
              <td className={styles.colAlert} />
            </tr>
          </tbody>
        </table>
      </div>
      {minimumCashBuffer > 0 && (
        <div style={{ padding: '8px 16px', fontSize: 12, color: '#6c757d', borderTop: '1px solid #e9ecef' }}>
          <i className="fas fa-info-circle" style={{ marginRight: 4 }} />
          Tiền khả dụng = Số dư cuối − Chi bắt buộc − Đệm tối thiểu ({fmtFull(minimumCashBuffer)} VND)
        </div>
      )}
    </div>
  );
};

export default ForecastTable;
