import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Button,
  dispatchAppToast,
  type SelectOption,
  LinErpListFilterBar,
  Select,
  SearchInput,
} from '@linm-soft-org/linm-web-common-components';
import type { ActiveCompanyItem } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { fpcService } from '../../../services/fpc/service';
import type { DailyCashForecastDto, CashForecastSummaryLineDto, PlanVersionDto } from '../../../services/fpc/types';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { getReportLabel } from '../../../constants/reportPageLabels';
import { createCompanySearchConfig } from '../../../components/search/companySearchConfig';
import CategoryBreakdown from './components/CategoryBreakdown';
import ForecastTable from './components/ForecastTable';
import styles from './DailyCashForecastPage.module.css';

const TEST_ID = 'daily-cash-forecast';
const labels = {
  pageTitle: getReportLabel('dailyCashForecast', 'pageTitle'),
  pageSubtitle: getReportLabel('dailyCashForecast', 'pageSubtitle'),
  labelOpeningBalance: getReportLabel('dailyCashForecast', 'labelOpeningBalance'),
  labelTotalInflow: getReportLabel('dailyCashForecast', 'labelTotalInflow'),
  labelTotalOutflow: getReportLabel('dailyCashForecast', 'labelTotalOutflow'),
  labelClosingAvailable: getReportLabel('dailyCashForecast', 'labelClosingAvailable'),
  labelMandatoryOutflow: 'Chi bắt buộc',
  labelSummaryTitle: getReportLabel('dailyCashForecast', 'labelSummaryTitle'),
  btnExport: getReportLabel('dailyCashForecast', 'btnExport'),
  filterBranch: getReportLabel('dailyCashForecast', 'filterBranch'),
  filterPlanVersion: getReportLabel('dailyCashForecast', 'filterPlanVersion'),
  filterDateLabel: getReportLabel('dailyCashForecast', 'filterDateLabel'),
};

function todayISO(): string {
  const d = new Date();
  return d.toISOString().slice(0, 10);
}

function DailyCashForecastPage() {
  const dispatch = useAppDispatch();

  // ── Filter state ──
  const [forecastDate, setForecastDate] = useState(todayISO());
  const [forecastDateTo, setForecastDateTo] = useState(todayISO());
  const [companyCode, setCompanyCode] = useState('');
  const [planVersionId, setPlanVersionId] = useState('');

  // ── Company search config ──
  const companySearchConfig = useMemo(() => createCompanySearchConfig(), []);

  // ── Selected company display ──
  const [selectedCompany, setSelectedCompany] = useState<ActiveCompanyItem | null>(null);

  // ── Data state ──
  const [data, setData] = useState<DailyCashForecastDto | null>(null);
  const [planVersions, setPlanVersions] = useState<PlanVersionDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [initialLoading, setInitialLoading] = useState(true);
  const [exporting, setExporting] = useState(false);
  const [printModalOpen, setPrintModalOpen] = useState(false);

  // ── Plan version options ──
  const planVersionOptions: SelectOption[] = useMemo(
    () => [
      { value: '', label: 'Tất cả' },
      ...planVersions.map(pv => ({ value: pv.id, label: `${pv.name} (${pv.planCode})` })),
    ],
    [planVersions],
  );

  // ── Handle load ──
  const handleLoad = useCallback(() => {
    setLoading(true);
    // Nếu from ≠ to → range mode, gửi fromDate+toDate
    // Nếu from == to → backward compatible single date
    const isRange = forecastDate !== forecastDateTo;
    const params: Parameters<typeof fpcService.getDailyForecast>[0] = isRange
      ? {
          fromDate: forecastDate,
          toDate: forecastDateTo,
          companyCode: companyCode || undefined,
          planVersionId: planVersionId || undefined,
        }
      : {
          date: forecastDate || todayISO(),
          companyCode: companyCode || undefined,
          planVersionId: planVersionId || undefined,
        };
    fpcService
      .getDailyForecast(params)
      .then((result) => {
        setData(result);
      })
      .catch(err => {
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Không thể tải dự báo dòng tiền.'),
          type: 'warning',
        });
        setData(null);
      })
      .finally(() => {
        setLoading(false);
        setInitialLoading(false);
      });
  }, [forecastDate, forecastDateTo, companyCode, planVersionId, dispatch]);

  // ── Handle export Excel ──
  const handleExport = useCallback(async () => {
    setExporting(true);
    try {
      const params = new URLSearchParams();
      params.set('date', forecastDate);
      if (companyCode) params.set('companyCode', companyCode);
      if (planVersionId) params.set('planVersionId', planVersionId);
      const exportUrl = `/fpc/daily-forecast/export-excel?${params.toString()}`;
      const response = await fetch(exportUrl, {
        headers: { Accept: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' },
      });
      if (!response.ok) throw new Error(`Export failed: ${response.status}`);
      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `DuBaoDongTien_${forecastDate}.xlsx`);
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
      dispatchAppToast(dispatch, { message: 'Xuất Excel thành công', type: 'success' });
    } catch (err) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Xuất Excel thất bại'),
        type: 'error',
      });
    } finally {
      setExporting(false);
    }
  }, [forecastDate, companyCode, planVersionId, dispatch]);

  // ── Handle print (scoped) ──
  const handlePrint = useCallback(() => {
    setPrintModalOpen(true);
  }, []);

  const handlePrintConfirm = useCallback(() => {
    setPrintModalOpen(false);
    document.body.classList.add('lin-report-printing');
    window.print();
    document.body.classList.remove('lin-report-printing');
  }, []);

  // ── Load plan versions on mount ──
  useEffect(() => {
    fpcService
      .getPlanList()
      .then(setPlanVersions)
      .catch(() => {});
  }, []);

  // ── Auto-load on first render ──
  useEffect(() => {
    handleLoad();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ── Format currency helper ──
  const fmt = (value: number): string => {
    if (value == null || Number.isNaN(value)) return '—';
    const abs = Math.abs(value);
    const sign = value < 0 ? '-' : '';
    if (abs >= 1_000_000_000) return `${sign}${(abs / 1_000_000_000).toFixed(2)} tỷ`;
    if (abs >= 1_000_000) return `${sign}${(abs / 1_000_000).toFixed(0)} tr`;
    return `${sign}${abs.toLocaleString('vi-VN')}`;
  };

  // ── Filter bar ──
  const listFilters = useMemo(
    () => (
      <ForecastFilterBar
        fromDate={forecastDate}
        toDate={forecastDateTo}
        onDateFromToChange={(from, to) => {
          setForecastDate(from ?? todayISO());
          setForecastDateTo(to ?? todayISO());
        }}
        companyCode={companyCode}
        onCompanyChange={(code) => setCompanyCode(code)}
        selectedCompany={selectedCompany}
        onCompanySelected={setSelectedCompany}
        companySearchConfig={companySearchConfig}
        planVersionId={planVersionId}
        onPlanVersionChange={setPlanVersionId}
        planVersionOptions={planVersionOptions}
        onSearch={handleLoad}
        loading={loading}
      />
    ),
    [forecastDate, forecastDateTo, companyCode, selectedCompany, companySearchConfig, planVersionId, planVersionOptions, handleLoad, loading],
  );

  return (
    <div
      className={styles.reportListRoot}
      data-report-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <div className={styles.page}>
        {/* ── Header + Toolbar ── */}
        <div className={styles.pageHeader}>
          <div className={styles.titleBlock}>
            <h1 className={styles.title}>
              <i className="fas fa-chart-line" />
              {labels.pageTitle}
            </h1>
            <p className={styles.subtitle}>
              Dự báo dòng tiền{forecastDate !== forecastDateTo
                ? ` từ ${new Date(forecastDate).toLocaleDateString('vi-VN')} đến ${new Date(forecastDateTo).toLocaleDateString('vi-VN')}`
                : ` ngày ${new Date(forecastDate).toLocaleDateString('vi-VN')}`
              }
              {data?.forecastDate && <> · Cập nhật: {new Date(data.forecastDate).toLocaleString('vi-VN')}</>}
            </p>
          </div>
          <div className={styles.headerActions}>
            <Button
              variant="secondary"
              size="md"
              onClick={handleLoad}
              loading={loading}
              data-testid={`${TEST_ID}-toolbar-refresh-btn`}
            >
              <i className="fas fa-sync-alt" style={{ marginRight: 6 }} />
              {getReportLabel('dailyCashForecast', 'btnRefresh')}
            </Button>
            <Button
              variant="secondary"
              size="md"
              onClick={handlePrint}
              disabled={!data}
              data-testid={`${TEST_ID}-toolbar-print-btn`}
            >
              <i className="fas fa-print" style={{ marginRight: 6 }} />
              In
            </Button>
            <Button
              variant="secondary"
              size="md"
              onClick={handleExport}
              loading={exporting}
              disabled={!data}
              data-testid={`${TEST_ID}-export`}
            >
              <i className="fas fa-file-excel" style={{ marginRight: 6 }} />
              {labels.btnExport}
            </Button>
          </div>
        </div>

        {/* ── Filters ── */}
        <div className={styles.filtersBar}>
          {listFilters}
        </div>

        {/* ── Summary cards ── */}
        {data && !initialLoading && (
          <div className={styles.summaryBar}>
            <div className={styles.summaryItem}>
              <label>{labels.labelOpeningBalance}</label>
              <strong>{fmt(data.openingBalance)}</strong>
            </div>
            <div className={styles.summaryItem}>
              <label>{labels.labelTotalInflow}</label>
              <strong className={styles.positive}>+{fmt(data.totalInflow)}</strong>
            </div>
            <div className={styles.summaryItem}>
              <label>{labels.labelTotalOutflow}</label>
              <strong className={styles.negative}>-{fmt(Math.abs(data.totalOutflow))}</strong>
            </div>
            <div className={styles.summaryItem}>
              <label>{labels.labelMandatoryOutflow}</label>
              <strong>{fmt(data.mandatoryOutflow)}</strong>
            </div>
            <div className={styles.summaryItem}>
              <label>{labels.labelClosingAvailable}</label>
              <strong className={data.availableBalance >= 0 ? styles.positive : styles.negative}>
                {fmt(data.availableBalance)}
              </strong>
            </div>
          </div>
        )}

        {/* ── Loading state ── */}
        {loading && initialLoading && (
          <div className={styles.tableSkeleton}>
            <div className={styles.skeletonRow} />
            <div className={styles.skeletonRow} />
            <div className={styles.skeletonRow} />
            <div className={styles.skeletonRow} />
          </div>
        )}

        {/* ── Empty state ── */}
        {!data && !loading && !initialLoading && (
          <div className={styles.tableEmpty}>
            <i className="fas fa-search-dollar" />
            <p>Chọn bộ lọc và bấm <strong>Xem</strong> để hiển thị dự báo dòng tiền</p>
          </div>
        )}

        {/* ── Forecast days table ── */}
        {data && data.days && data.days.length > 0 && (
          <ForecastTable
            days={data.days}
            minimumCashBuffer={data.minimumCashBuffer}
          />
        )}

        {/* ── Category breakdown ── */}
        {data && (
          <CategoryBreakdown
            inflowLines={data.inflowLines}
            outflowLines={data.outflowLines}
            loading={false}
          />
        )}
      </div>

      {/* ── Print scope modal ── */}
      {printModalOpen && (
        <div className={styles.modalOverlay} onClick={() => setPrintModalOpen(false)}>
          <div className={styles.modalContent} onClick={e => e.stopPropagation()}>
            <h3 className={styles.modalTitle}>In báo cáo</h3>
            <p className={styles.modalText}>
              Báo cáo sẽ được in với bố cục gọn, bao gồm tiêu đề, bộ lọc đã áp dụng, bảng dữ liệu và phân tích.
            </p>
            <div className={styles.modalActions}>
              <Button variant="secondary" size="md" onClick={() => setPrintModalOpen(false)}>
                Huỷ
              </Button>
              <Button variant="primary" size="md" onClick={handlePrintConfirm}>
                In
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/** Inner filter bar component using LinErpListFilterBar. */
interface ForecastFilterBarProps {
  fromDate: string;
  toDate: string;
  onDateFromToChange: (from?: string, to?: string) => void;
  companyCode: string;
  onCompanyChange: (code: string) => void;
  selectedCompany: ActiveCompanyItem | null;
  onCompanySelected: (item: ActiveCompanyItem | null) => void;
  companySearchConfig: ReturnType<typeof createCompanySearchConfig>;
  planVersionId: string;
  onPlanVersionChange: (id: string) => void;
  planVersionOptions: SelectOption[];
  onSearch: () => void;
  loading: boolean;
}

const ForecastFilterBar: React.FC<ForecastFilterBarProps> = ({
  fromDate, toDate, onDateFromToChange,
  companyCode, onCompanyChange, selectedCompany, onCompanySelected, companySearchConfig,
  planVersionId, onPlanVersionChange,
  planVersionOptions,
  onSearch, loading,
}) => {
  const leading = useMemo(
    () => (
      <>
        <SearchInput
          config={companySearchConfig}
          value={companyCode}
          primaryDisplay={selectedCompany?.code}
          secondaryDisplay={selectedCompany?.name}
          onChange={(item) => {
            onCompanyChange(item.code ?? item.id);
            onCompanySelected(item);
          }}
          onClear={() => {
            onCompanyChange('');
            onCompanySelected(null);
          }}
          showLabel
          label={labels.filterBranch}
          placeholder="Chọn chi nhánh..."
        />
        <Select
          label={labels.filterPlanVersion}
          value={planVersionId}
          onChange={e => onPlanVersionChange(e.target.value)}
          options={planVersionOptions}
          size="small"
          data-testid={`${TEST_ID}-filter-plan-version`}
        />
      </>
    ),
    [companyCode, companySearchConfig, selectedCompany, onCompanyChange, onCompanySelected,
     planVersionId, planVersionOptions, onPlanVersionChange],
  );

  return (
    <LinErpListFilterBar
      testIdPrefix={TEST_ID}
      fromDate={fromDate}
      toDate={toDate}
      onDateChange={onDateFromToChange}
      dateLabel={labels.filterDateLabel}
      expandDateRangeAriaLabel="Thêm ngày kết thúc"
      onSearch={onSearch}
      searchAriaLabel="Xem"
      loading={loading}
      leading={leading}
    />
  );
};

export default DailyCashForecastPage;
