import React from 'react';
import type { CashForecastSummaryLineDto } from '../../../../services/fpc/types';
import styles from '../DailyCashForecastPage.module.css';

/**
 * Format a number as VND compact for display in breakdown cards.
 */
function formatCurrency(value: number): string {
  if (value == null || Number.isNaN(value)) return '—';
  const abs = Math.abs(value);
  if (abs >= 1_000_000_000) {
    return `${(abs / 1_000_000_000).toFixed(2)} tỷ`;
  }
  if (abs >= 1_000_000) {
    return `${(abs / 1_000_000).toFixed(1)} tr`;
  }
  return abs.toLocaleString('vi-VN');
}

export interface CategoryBreakdownProps {
  inflowLines: CashForecastSummaryLineDto[];
  outflowLines: CashForecastSummaryLineDto[];
  loading?: boolean;
}

const CategoryBreakdown: React.FC<CategoryBreakdownProps> = ({
  inflowLines,
  outflowLines,
  loading,
}) => {
  if (loading) {
    return (
      <div className={styles.breakdownGrid}>
        <div className={styles.breakdownCard}>
          <div className={styles.skeletonRow} style={{ height: 20, marginBottom: 8, width: '40%' }} />
          <div className={styles.skeletonRow} style={{ height: 16, width: '80%' }} />
          <div className={styles.skeletonRow} style={{ height: 16, width: '60%' }} />
        </div>
        <div className={styles.breakdownCard}>
          <div className={styles.skeletonRow} style={{ height: 20, marginBottom: 8, width: '40%' }} />
          <div className={styles.skeletonRow} style={{ height: 16, width: '80%' }} />
          <div className={styles.skeletonRow} style={{ height: 16, width: '60%' }} />
        </div>
      </div>
    );
  }

  const inflowTotal = inflowLines.reduce((s, l) => s + l.amount, 0);
  const outflowTotal = outflowLines.reduce((s, l) => s + l.amount, 0);

  return (
    <div className={styles.breakdownGrid}>
      {/* Inflow section */}
      <div className={styles.breakdownCard}>
        <div className={styles.breakdownHeader}>
          <i className="fas fa-arrow-down" style={{ color: 'var(--color-success, #52c41a)' }} />
          <span className={styles.breakdownTitle}>Dòng thu</span>
          <span className={styles.breakdownTotal}>{formatCurrency(inflowTotal)}</span>
        </div>
        {inflowLines.length === 0 ? (
          <div className={styles.breakdownEmpty}>Chưa có dữ liệu</div>
        ) : (
          <ul className={styles.breakdownList}>
            {inflowLines.map(item => (
              <li key={item.categoryCode} className={styles.breakdownItem}>
                <div className={styles.breakdownInfo}>
                  <span className={styles.breakdownName}>{item.categoryName}</span>
                  <span className={styles.breakdownCount}>
                    {item.lineCount} khoản
                  </span>
                </div>
                <div className={styles.breakdownBarWrap}>
                  <div
                    className={styles.breakdownBar}
                    style={{
                      width: inflowTotal > 0 ? `${(item.amount / inflowTotal) * 100}%` : '0%',
                      backgroundColor: 'var(--color-success, #52c41a)',
                    }}
                  />
                </div>
                <span className={styles.breakdownValue}>{formatCurrency(item.amount)}</span>
              </li>
            ))}
          </ul>
        )}
      </div>

      {/* Outflow section */}
      <div className={styles.breakdownCard}>
        <div className={styles.breakdownHeader}>
          <i className="fas fa-arrow-up" style={{ color: 'var(--color-danger, #ff4d4f)' }} />
          <span className={styles.breakdownTitle}>Dòng chi</span>
          <span className={styles.breakdownTotal}>{formatCurrency(outflowTotal)}</span>
        </div>
        {outflowLines.length === 0 ? (
          <div className={styles.breakdownEmpty}>Chưa có dữ liệu</div>
        ) : (
          <ul className={styles.breakdownList}>
            {outflowLines.map(item => (
              <li key={item.categoryCode} className={styles.breakdownItem}>
                <div className={styles.breakdownInfo}>
                  <span className={styles.breakdownName}>{item.categoryName}</span>
                  <span className={styles.breakdownCount}>
                    {item.lineCount} khoản
                  </span>
                </div>
                <div className={styles.breakdownBarWrap}>
                  <div
                    className={styles.breakdownBar}
                    style={{
                      width: outflowTotal > 0 ? `${(item.amount / outflowTotal) * 100}%` : '0%',
                      backgroundColor: 'var(--color-danger, #ff4d4f)',
                    }}
                  />
                </div>
                <span className={styles.breakdownValue}>{formatCurrency(item.amount)}</span>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};

export default CategoryBreakdown;
